import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen font-sans bg-secondary text-[15px] leading-relaxed">
      {/* Sidebar */}
      <aside className="sidebar w-56 border-r border-pink-100 p-4 flex flex-col shadow-sm bg-pink-50">
        {/* Logo / Profile */}
        <Link
          to="/"
          className="flex items-center mb-6 p-2 rounded-lg hover:bg-primary/20 transition"
        >
          <div className="w-10 h-10 rounded-full bg-primary flex items-center justify-center text-white font-bold shadow-sm">
            A
          </div>
          <div className="ml-2">
            <p className="text-sm font-semibold text-dark">Admin</p>
            <p className="text-xs text-pink-600">DTP Flower Shop</p>
          </div>
        </Link>

        {/* Navigation */}
        <nav className="flex flex-col gap-1 flex-1">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-2 px-3 py-2 rounded-md transition-all duration-200 ${
                location.pathname === item.path
                  ? "bg-primary/30 text-primary font-semibold shadow-sm"
                  : "text-dark hover:bg-primary/10 hover:text-primary"
              }`}
            >
              <span>{item.icon}</span>
              <span className="text-sm">{item.name}</span>
            </Link>
          ))}

          {/* Xem trang web */}
          <a
            href="/"
            target="_self"
            className="mt-auto block w-full text-center bg-primary text-white py-2 rounded-md text-sm font-semibold shadow hover:bg-primary/90 transition"
          >
            🌸 Xem trang web
          </a>
        </nav>
      </aside>

      {/* Main content */}
      <main
        className={`flex-1 p-5 overflow-y-auto transition-colors duration-300 ${
          isDashboard ? "bg-pink-50" : "bg-secondary"
        }`}
      >
        {/* Header */}
        <div className="flex justify-between items-center mb-4">
          <h1
            className={`text-lg font-semibold ${
              isDashboard ? "text-primary" : "text-dark"
            }`}
          >
            {currentPage || "DASHBOARD"}
          </h1>
        </div>

        {/* Page content card */}
        <div
          className={`p-5 rounded-xl shadow-sm min-h-[70vh] transition-colors duration-300 ${
            isDashboard ? "bg-white/90" : "bg-white"
          }`}
        >
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
